// Extract and normalize call metadata from Aircall webhook
const webhookData = $input.first().json;

const callData = {
  // Call identifiers
  call_id: webhookData.data?.id || webhookData.call_id,
  external_id: `aircall_${webhookData.data?.id}`,

  // Timestamps
  started_at: webhookData.data?.started_at,
  ended_at: webhookData.data?.answered_at ? 
    new Date(webhookData.data.answered_at * 1000 + (webhookData.data.duration * 1000)).toISOString() :
    new Date().toISOString(),
  duration_seconds: webhookData.data?.duration || 0,

  // Participants
  caller_number: webhookData.data?.raw_digits || webhookData.data?.number?.digits,
  caller_name: webhookData.data?.contact?.first_name ? 
    `${webhookData.data.contact.first_name} ${webhookData.data.contact.last_name || ''}`.trim() :
    'Unknown Caller',
  agent_id: webhookData.data?.user?.id,
  agent_name: webhookData.data?.user?.name,
  agent_email: webhookData.data?.user?.email,

  // Call details
  direction: webhookData.data?.direction || 'inbound',
  call_type: webhookData.data?.call_type || 'voice',
  status: webhookData.data?.status || 'done',

  // Recording info
  recording_url: webhookData.data?.recording,
  has_recording: !!webhookData.data?.recording,

  // HubSpot mapping
  hubspot_contact_id: webhookData.data?.contact?.hubspot_id || null,

  // Processing metadata
  processed_at: new Date().toISOString(),
  workflow_version: '1.0.0',
  source: 'aircall'
};

return { json: callData };

