// Log calls without recordings for monitoring
const callData = $input.first().json;

console.log(`Call ${callData.call_id} completed without recording`);

return {
  json: {
    status: 'no_recording',
    call_id: callData.call_id,
    reason: 'Call completed but no recording available',
    timestamp: new Date().toISOString()
  }
};
